seed_files.processor.py:
"""Task processing pipeline with stages and hooks.

The pipeline processes tasks through three stages:
1. validate - Check task data integrity
2. transform - Apply business logic transformations
3. persist - Write results to destinations

Each stage supports pre/post hooks for extensibility.
"""
from typing import List, Dict, Callable, Optional, Any
from hooks import get_default_hooks
from destinations import DestinationMap


class Task:
    """A unit of work to be processed by the pipeline."""

    def __init__(self, task_id: str, data: Dict[str, Any], priority: int = 0):
        self.task_id = task_id
        self.data = data
        self.priority = priority
        self.status = 'pending'
        self.result = None
        self.errors: List[str] = []

    def __repr__(self):
        return f"Task(id={self.task_id!r}, priority={self.priority}, status={self.status!r})"


class TaskProcessor:
    """Pipeline processor that runs tasks through validate -> transform -> persist."""

    def __init__(self, tasks: List[Task], destination_map: DestinationMap):
        self.tasks = list(tasks)
        self.destination_map = destination_map
        self._hooks: Dict[str, List[Callable]] = {
            'pre_validate': [],
            'post_validate': [],
            'pre_transform': [],
            'post_transform': [],
            'pre_persist': [],
            'post_persist': [],
        }
        self._results: Dict[str, Any] = {}

        # Register default hooks
        for hook_name, hook_fn in get_default_hooks():
            self.register_hook(hook_name, hook_fn)

    def register_hook(self, stage: str, hook: Callable) -> None:
        """Register a hook function for a pipeline stage."""
        if stage in self._hooks:
            self._hooks[stage].append(hook)

    def _run_hooks(self, stage: str) -> None:
        """Run all hooks registered for a stage."""
        for hook in self._hooks.get(stage, []):
            hook(self)

    def run_pipeline(self) -> Dict[str, Any]:
        """Execute the full pipeline: validate -> transform -> persist."""
        self._validate_stage()
        self._transform_stage()
        self._persist_stage()
        return self._results

    def _validate_stage(self) -> None:
        """Stage 1: Validate all tasks."""
        self._run_hooks('pre_validate')

        for task in self.tasks:
            if not task.data:
                task.errors.append('Task data is empty')
                task.status = 'invalid'
            elif 'value' not in task.data:
                task.errors.append('Task data missing required field: value')
                task.status = 'invalid'
            else:
                task.status = 'validated'

        self._run_hooks('post_validate')

    def _transform_stage(self) -> None:
        """Stage 2: Apply transformations to validated tasks."""
        self._run_hooks('pre_transform')

        for task in self.tasks:
            if task.status != 'validated':
                continue
            # Business logic: double the value and add a computed field
            original_value = task.data['value']
            task.data['transformed_value'] = original_value * 2
            task.data['label'] = f"{task.task_id}_processed"
            task.result = task.data['transformed_value']
            task.status = 'transformed'

        self._run_hooks('post_transform')

    def _persist_stage(self) -> None:
        """Stage 3: Persist transformed task results to their destinations.

        Each task is paired with its destination by position in the list.
        The destination_map maintains an ordered list of output slots.
        """
        self._run_hooks('pre_persist')

        destinations = self.destination_map.get_slots()

        for task, dest in zip(self.tasks, destinations):
            if task.status != 'transformed':
                self._results[task.task_id] = {
                    'destination': None,
                    'status': 'skipped',
                    'errors': task.errors,
                }
                continue

            self.destination_map.write(dest, {
                'task_id': task.task_id,
                'result': task.result,
                'data': task.data,
            })

            self._results[task.task_id] = {
                'destination': dest,
                'status': 'persisted',
                'result': task.result,
            }

        self._run_hooks('post_persist')

    def get_results(self) -> Dict[str, Any]:
        """Return the pipeline results."""
        return dict(self._results)

    def get_tasks(self) -> List[Task]:
        """Return the current task list."""
        return list(self.tasks)

seed_files.destinations.py:
"""Destination mapping for the task processing pipeline.

Each task is assigned a destination slot based on its insertion order.
The DestinationMap tracks which slots exist and stores output data.
"""
from typing import List, Dict, Any, Optional


class DestinationMap:
    """Maps task positions to output destination slots.

    When tasks are registered, they get assigned slots in order:
    task 0 -> slot_0, task 1 -> slot_1, etc.

    The persist stage uses positional pairing (zip) to match
    tasks to their assigned slots.
    """

    def __init__(self, task_ids: List[str]):
        """Initialize destination slots for each task.

        Args:
            task_ids: List of task IDs in their original insertion order.
                     Each gets assigned a sequential slot.
        """
        self._slots: List[str] = []
        self._slot_data: Dict[str, Any] = {}
        self._task_to_slot: Dict[str, str] = {}

        for i, task_id in enumerate(task_ids):
            slot_name = f"slot_{i}"
            self._slots.append(slot_name)
            self._slot_data[slot_name] = None
            self._task_to_slot[task_id] = slot_name

    def get_slots(self) -> List[str]:
        """Return the ordered list of destination slot names."""
        return list(self._slots)

    def get_slot_for_task(self, task_id: str) -> Optional[str]:
        """Look up the destination slot assigned to a specific task ID."""
        return self._task_to_slot.get(task_id)

    def write(self, slot_name: str, data: Any) -> None:
        """Write data to a destination slot."""
        if slot_name not in self._slot_data:
            raise ValueError(f"Unknown destination slot: {slot_name}")
        self._slot_data[slot_name] = data

    def read(self, slot_name: str) -> Any:
        """Read data from a destination slot."""
        if slot_name not in self._slot_data:
            raise ValueError(f"Unknown destination slot: {slot_name}")
        return self._slot_data[slot_name]

    def get_all_data(self) -> Dict[str, Any]:
        """Return all slot data as a dict."""
        return dict(self._slot_data)

    def get_task_slot_mapping(self) -> Dict[str, str]:
        """Return the task_id -> slot_name mapping."""
        return dict(self._task_to_slot)
